import{_ as i,o as a,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"2022年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2022年/核心总结.md","filePath":"01_letters/2022年/核心总结.md"}'),o={name:"01_letters/2022年/核心总结.md"};function r(u,l,h,n,d,q){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="_2022年巴菲特致股东信核心总结" tabindex="-1">2022年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2022年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2022年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>GAAP净利润出现巨大季度波动（二季度亏损438亿美元）</li><li>营业利润308亿美元，创纪录</li><li>每股市场价值增长4.0%，大幅跑赢标普500的-18.1%</li><li>58年复合年化收益率19.8%</li></ul><h2 id="收购与投资" tabindex="-1">收购与投资 <a class="header-anchor" href="#收购与投资" aria-label="Permalink to &quot;收购与投资&quot;">​</a></h2><ul><li>收购Alleghany保险公司（由Joe Brandon领导）</li><li>保险浮存金从1470亿增至1640亿美元</li><li>浮存金自1967年来增长8000倍</li><li>成为8家标普500公司最大股东：美国运通、美国银行、雪佛龙、可口可乐、惠普、穆迪、西方石油、派拉蒙</li></ul><h2 id="四大巨头更新" tabindex="-1">四大巨头更新 <a class="header-anchor" href="#四大巨头更新" aria-label="Permalink to &quot;四大巨头更新&quot;">​</a></h2><ul><li>BNSF盈利59亿美元</li><li>BHE盈利43亿美元</li><li>两家公司都超过标普500中30亿美元的盈利门槛</li><li>保险业务价值可比BNSF或BHE</li></ul><h2 id="秘诀所在-少数赢家创造奇迹" tabindex="-1">秘诀所在：少数赢家创造奇迹 <a class="header-anchor" href="#秘诀所在-少数赢家创造奇迹" aria-label="Permalink to &quot;秘诀所在：少数赢家创造奇迹&quot;">​</a></h2><ul><li>可口可乐：1994年成本13亿，2022年股息7.04亿，市值250亿</li><li>美国运通：1995年成本13亿，2022年股息3.02亿，市值220亿</li><li>股息每年增长，如同生日一样确定</li><li>&quot;随着鲜花的绽放，杂草的重要性就会消退&quot;</li><li>只需要少数几个赢家就能创造奇迹</li></ul><h2 id="回购的力量" tabindex="-1">回购的力量 <a class="header-anchor" href="#回购的力量" aria-label="Permalink to &quot;回购的力量&quot;">​</a></h2><ul><li>2022年回购1.2%流通股</li><li>苹果和美国运通的回购增加伯克希尔持股比例</li><li>每股内在价值有微小增长</li><li>反驳&quot;回购有害论&quot;：这是经济学文盲或巧舌如簧的煽动家的言论</li></ul><h2 id="gaap利润的误导性" tabindex="-1">GAAP利润的误导性 <a class="header-anchor" href="#gaap利润的误导性" aria-label="Permalink to &quot;GAAP利润的误导性&quot;">​</a></h2><ul><li>2022年季度GAAP利润剧烈波动：70亿→93亿→78亿→67亿</li><li>运营收益：55亿→-438亿→-27亿→182亿</li><li>媒体不加批判地将GAAP波动作为头条，完全误导投资者</li></ul><h2 id="美国税收贡献" tabindex="-1">美国税收贡献 <a class="header-anchor" href="#美国税收贡献" aria-label="Permalink to &quot;美国税收贡献&quot;">​</a></h2><ul><li>2012-2021年十年间缴纳联邦所得税320亿美元</li><li>占全美企业所得税收入的千分之一</li><li>如果有1000个纳税人缴同样税款，其他企业和家庭都不需要缴税</li><li>形象比喻：320亿美元堆起来高21英里（飞机巡航高度3倍）</li><li>&quot;我在办公室已经缴纳了&quot;</li></ul><h2 id="标普500对比" tabindex="-1">标普500对比 <a class="header-anchor" href="#标普500对比" aria-label="Permalink to &quot;标普500对比&quot;">​</a></h2><ul><li>2021年标普500公司合计盈利1.8万亿美元</li><li>只有128家盈利超过30亿美元</li><li>23家亏损</li><li>伯克希尔拥有10家盈利超30亿美元的巨头（8家上市公司+2家控股）</li></ul><h2 id="资本主义两面性" tabindex="-1">资本主义两面性 <a class="header-anchor" href="#资本主义两面性" aria-label="Permalink to &quot;资本主义两面性&quot;">​</a></h2><ul><li>熊彼特的&quot;创造性破坏&quot;</li><li>系统产生失败者，但也提供更好的产品和服务</li><li>控股企业从不以便宜价格出售（除非被迫）</li><li>公开股票经常以愚蠢价格交易</li></ul><h2 id="巴菲特自我评价" tabindex="-1">巴菲特自我评价 <a class="header-anchor" href="#巴菲特自我评价" aria-label="Permalink to &quot;巴菲特自我评价&quot;">​</a></h2><ul><li>58年管理中大多数资本配置决策表现平平</li><li>约12个真正好的决策（每5年一个）</li><li>糟糕决策曾被运气拯救（美航、所罗门）</li><li>成功源于少数赢家和长期投资优势</li></ul><h2 id="查理·芒格语录" tabindex="-1">查理·芒格语录 <a class="header-anchor" href="#查理·芒格语录" aria-label="Permalink to &quot;查理·芒格语录&quot;">​</a></h2><ul><li>&quot;世界上充满了愚蠢的赌徒，他们的表现不会像耐心的投资者那样好&quot;</li><li>&quot;我只想知道我会死在哪里，这样我就永远不会去那里&quot;</li><li>&quot;耐心是可以学会的&quot;</li><li>&quot;投资中没有100%确定的事情，杠杆是危险的&quot;</li><li>&quot;沃伦，多想想。你很聪明，而我是对的&quot;</li></ul><h2 id="美国信念" tabindex="-1">美国信念 <a class="header-anchor" href="#美国信念" aria-label="Permalink to &quot;美国信念&quot;">​</a></h2><ul><li>巴菲特投资80年（超过美国寿命三分之一）</li><li>从未见过做空美国长期是明智的</li><li>美国的活力对伯克希尔成功贡献巨大</li><li>美国顺风有时平静，但总是回归</li></ul><h2 id="股东特质" tabindex="-1">股东特质 <a class="header-anchor" href="#股东特质" aria-label="Permalink to &quot;股东特质&quot;">​</a></h2><ul><li>伯克希尔股东属于&quot;一旦储蓄、始终储蓄&quot;类型</li><li>最终会将大部分资金捐赠给慈善机构</li><li>极少选择&quot;炫耀性资产&quot;或&quot;家族王朝&quot;</li><li>金钱的处置方式揭示人性</li></ul><h2 id="财务稳健" tabindex="-1">财务稳健 <a class="header-anchor" href="#财务稳健" aria-label="Permalink to &quot;财务稳健&quot;">​</a></h2><ul><li>永远持有大量现金和国债</li><li>避免导致资金紧张的行为</li><li>CEO永远担任首席风险官</li><li>未来CEO将以自己的钱购买伯克希尔股票</li><li>在伯克希尔，没有终点线</li></ul><h2 id="股东大会" tabindex="-1">股东大会 <a class="header-anchor" href="#股东大会" aria-label="Permalink to &quot;股东大会&quot;">​</a></h2><ul><li>2023年5月5-6日奥马哈</li><li>See&#39;s糖果两天销售400,309美元</li><li>每分钟10笔销售，101年产品基本不变</li><li>查理和巴菲特分别99岁和92岁</li></ul><h2 id="关键理念" tabindex="-1">关键理念 <a class="header-anchor" href="#关键理念" aria-label="Permalink to &quot;关键理念&quot;">​</a></h2><ul><li>&quot;我们是选企业者，不是选股者&quot;</li><li>股票市场是投票机，长期是称重机</li><li>找一个聪明的优质合作伙伴，仔细听他的话</li><li>一连串精彩的数字乘以零总是等于零</li></ul>',33)])])}const b=i(o,[["render",r]]);export{c as __pageData,b as default};
